  ('dietitian-moex-08544', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '依據勞動基準法，下列何者不合理？', '["勞工繼續工作四小時，至少應有三十分鐘之休息", "勞工每七日中至少應有一日之休息，作為例假", "男、女性員工因性別，得有不同的工資比例", "勞工每日正常工作時間不得超過八小時，每二週工作總時數不得超過八十四小時"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4b6eba7d8a3f", "answer_pdf_sha1": "153fd09b1e79", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08545', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列何者是正確的廚房設計與規劃？', '["扣除設備所占之固定面積外，其餘的工作區、走道、周邊設備之空間必須保留廚房總面積的70%以上", "廚房設備所占的面積不得超過廚房總面積的50%", "調味料庫房宜設置鍋爐附近，以方便取用", "牆面與地面宜為圓弧角至少為15 cm"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4b6eba7d8a3f", "answer_pdf_sha1": "153fd09b1e79", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08546', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '餐具之「殘留脂肪檢驗」常用下列何種色素？', '["藍色7號", "黃色5號", "紅色4號", "綠色3號"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4b6eba7d8a3f", "answer_pdf_sha1": "153fd09b1e79", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08547', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '為提高工作效率，工作枱的高度以下列何者較適宜？', '["50－60公分", "60－70公分", "70－80公分", "80－90公分"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4b6eba7d8a3f", "answer_pdf_sha1": "153fd09b1e79", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08548', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '餐具自動洗滌設施之條件，下列敘述何者錯誤？', '["沖洗槽應具有充足流動之水", "洗滌槽需具有43℃以上含清潔劑之熱水", "應設有溫度計、壓力計及洗潔劑偵測器，且每3個月應作校正", "水壓應在23磅/平方英吋以下"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4b6eba7d8a3f", "answer_pdf_sha1": "153fd09b1e79", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08549', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列敘述何者錯誤？', '["烹調完成的食物，冬天盡量於3~4小時內食用完畢", "所謂「hot foods hot, cold foods cold」是指冷食須保持在15℃以下，熱食須保持在45℃以上", "餐具消毒可用100℃沸水煮沸1分鐘以上之方式行之", "抹布消毒可用100℃沸水煮沸5分鐘以上之方式行之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4b6eba7d8a3f", "answer_pdf_sha1": "153fd09b1e79", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08550', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列有關品管的敘述，何者錯誤？', '["「80/20法則」又稱為「柏拉圖法則」", "「魚骨圖」用於分析要因", "研究因子的因果關係可用「關聯圖分析」", "傳統的品管觀念著重於製備過程的品管，非結果的抽樣"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4b6eba7d8a3f", "answer_pdf_sha1": "153fd09b1e79", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08551', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列有關黃豆製品之敘述，何者正確？', '["豆漿煮沸時會產生泡沫是因其含有植酸之故", "在豆漿中加入凝固劑將蛋白質凝固後，再加以壓榨，即為豆皮", "醬油及味噌均屬於黃豆醱酵食品", "納豆是我國特有的黃豆醱酵食品"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4b6eba7d8a3f", "answer_pdf_sha1": "153fd09b1e79", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-08552', 'dietitian', 'dietitian-moex-098-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '蛋白打發過程的四個階段依序為：', '["foamy stage→soft peaks stage→stiff peaks stage→dry peaks stage", "foamy stage→stiff peaks stage→soft peaks stage→dry peaks stage", "foamy stage→soft peaks stage→dry peaks stage→stiff peaks stage", "foamy stage→dry peaks stage→stiff peaks stage→soft peaks stage"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:50+00:00", "source_pdf_sha1": "4b6eba7d8a3f", "answer_pdf_sha1": "153fd09b1e79", "source_family": "moex-gov-tw", "moex": {"exam_code": "098140", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "098", "exam_name": "098年第二次醫事人員、中醫師、心理師、營養師、醫師分試 、法醫師", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
